// Читаем итоговую конфигурацию worker-ов, уже подготовленную на этапе bootstrap.
const routing = $('Задаём конфигурацию OpenCode').first().json

// Забираем все задачи из таблицы один раз и далее группируем их по worker-ам.
const allTasks = $('Получаем все задачи').all().map((item) => item.json)

function sortByQueuedAt(left, right) {
  return String(left.queued_at || '').localeCompare(String(right.queued_at || ''))
}

function parseModel(modelRef) {
  const normalized = String(modelRef || '').trim()
  const separatorIndex = normalized.indexOf('/')

  if (!normalized || separatorIndex <= 0 || separatorIndex === normalized.length - 1) {
    return null
  }

  return {
    providerID: normalized.slice(0, separatorIndex),
    modelID: normalized.slice(separatorIndex + 1),
  }
}

// Возвращаем по одному item на каждый worker.
// Сразу считаем число queued и active задач, чтобы дальше использовать штатные numeric-условия в If-нодах.
return Object.entries(routing.workers || {}).map(([workerAlias, workerConfig]) => {
  const workerTasks = allTasks
    .filter((task) => String(task.worker_alias || '').trim() === workerAlias)
    .sort(sortByQueuedAt)
  const queuedTasks = workerTasks.filter((task) => String(task.status || '').trim() === 'queued')
  const activeTasks = workerTasks.filter((task) => ['running', 'needs_input'].includes(String(task.status || '').trim()))

  return {
    json: {
      workerAlias,
      workerBaseUrl: String(workerConfig.baseUrl || '').trim(),
      authorizationHeader: String(workerConfig.authorizationHeader || '').trim(),
      sessionCreatePath: String(routing.endpoints?.sessionCreate || '').trim(),
      sessionMessagePath: String(routing.endpoints?.sessionMessage || '').trim(),
      messageListPath: String(routing.endpoints?.messageList || '').trim(),
      questionListPath: String(routing.endpoints?.questionList || '').trim(),
      questionReplyPath: String(routing.endpoints?.questionReply || '').trim(),
      questionRejectPath: String(routing.endpoints?.questionReject || '').trim(),
      sessionStatusPath: String(routing.endpoints?.sessionStatus || '').trim(),
      promptAsyncPath: String(routing.endpoints?.promptAsync || '').trim(),
      opencodeAgent: String(routing.defaultAgent || 'build').trim(),
      opencodeModel: parseModel(routing.defaultModel),
      workerTasks,
      queuedTasks,
      queuedTasksCount: queuedTasks.length,
      activeTasks,
      activeTasksCount: activeTasks.length,
    },
  }
})

// Берём пакет данных текущего worker-а, который уже содержит только queued задачи
// и количество активных задач этого worker-а.
const workerPackage = $('Готовим пакеты worker-ов').item.json
const queuedTasks = Array.isArray(workerPackage.queuedTasks) ? workerPackage.queuedTasks : []
const workerTasks = Array.isArray(workerPackage.workerTasks) ? workerPackage.workerTasks : []

// Приоритет всегда у зависимых задач.
// Если зависимых задач нет, берём самую раннюю обычную queued-задачу.
const dependentTasks = queuedTasks.filter((task) => String(task.parent_task_key || '').trim())
const regularTasks = queuedTasks.filter((task) => !String(task.parent_task_key || '').trim())
const selectedTask = dependentTasks[0] || regularTasks[0] || null

let context = {}
try {
  context = JSON.parse(String(selectedTask?.context_json || '{}'))
} catch {
  context = {}
}

const chatId = String(selectedTask?.chat_id || '').trim()
const sessionHistory = workerTasks
  .filter((task) => String(task.chat_id || '').trim() === chatId)
  .filter((task) => String(task.session_id || '').trim())

const latestSessionTask = sessionHistory[sessionHistory.length - 1] || null
const latestSessionId = String(latestSessionTask?.session_id || '').trim()
const newSessionRequested = Boolean(
  context.newSessionRequested ||
  context.flags?.['new-session'] ||
  context.flags?.['new_session'] ||
  context.flags?.['fresh-session'] ||
  context.flags?.['fresh_session']
)
const claimToken = `claim-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 10)}`

return {
  json: {
    task: selectedTask,
    parentTaskKey: String(selectedTask?.parent_task_key || '').trim(),
    parentMatchText: String(selectedTask?.parent_match_text || '').trim(),
    promptText: String(selectedTask?.prompt || '').trim(),
    latestSessionId,
    createNewSession: newSessionRequested || !latestSessionId,
    claimToken,
  },
}

return {
  json: {
    sessionId: String($('Выбираем кандидатную задачу').item.json.latestSessionId || '').trim(),
    launchError: '',
  },
}

// Нормализуем данные сессии после создания или переиспользования.
const sessionResponse = $json
const worker = $('Готовим пакеты worker-ов').item.json

const sessionId = String(sessionResponse.sessionId || sessionResponse.id || sessionResponse.data?.id || '').trim()
const launchError = sessionResponse.error
  ? String(sessionResponse.error.message || sessionResponse.error)
  : sessionId
    ? ''
    : 'OpenCode не вернул session id.'

function withSession(pathTemplate) {
  return sessionId && pathTemplate
    ? worker.workerBaseUrl + String(pathTemplate).replace(':id', sessionId)
    : ''
}

return {
  json: {
    sessionId,
    launchError,
    promptAsyncUrl: withSession(worker.promptAsyncPath),
    messageListUrl: withSession(worker.messageListPath),
    sessionMessageUrl: withSession(worker.sessionMessagePath),
    sessionStatusUrl: worker.workerBaseUrl + worker.sessionStatusPath,
    questionListUrl: worker.workerBaseUrl + worker.questionListPath,
  },
}

// В async-сценарии задача получает итог отдельно: сначала polling /session/status,
// затем чтение истории сообщений через GET /session/:id/message.
const task = $('Выбираем активную задачу').item.json.task
const rawItems = $('Получаем сообщения сессии OpenCode').all().map((item) => item.json)
const messages = rawItems
  .flatMap((item) => Array.isArray(item) ? item : [item])
  .filter(Boolean)

const assistantMessages = messages
  .filter((message) => String(message.info?.role || '') === 'assistant')
  .sort((left, right) => Number(left.info?.time?.created || 0) - Number(right.info?.time?.created || 0))

const latestAssistant = assistantMessages[assistantMessages.length - 1] || null

if (!latestAssistant) {
  return {
    json: {
      resultStatus: 'failed',
      optionsCount: 0,
      questionText: '',
      optionsJson: '[]',
      replyText: `Задача ${task.task_key} завершилась без итогового ответа OpenCode.`,
    },
  }
}

const assistantError = latestAssistant.info?.error
if (assistantError) {
  const errorMessage = String(assistantError.data?.message || assistantError.message || assistantError.name || 'OpenCode завершился с ошибкой.')
  return {
    json: {
      resultStatus: 'failed',
      optionsCount: 0,
      questionText: '',
      optionsJson: '[]',
      replyText: `Задача ${task.task_key} завершилась ошибкой OpenCode: ${errorMessage}`,
    },
  }
}

const textParts = Array.isArray(latestAssistant.parts)
  ? latestAssistant.parts
      .filter((part) => String(part.type || '') === 'text')
      .map((part) => String(part.text || part.content || '').trim())
      .filter(Boolean)
  : []

const rawText = textParts.join('\n').trim() || JSON.stringify(latestAssistant)

return {
  json: {
    resultStatus: 'done',
    optionsCount: 0,
    questionText: '',
    optionsJson: '[]',
    replyText: `Задача ${task.task_key} завершена.\n\n${rawText}`,
  },
}

let pendingMeta = {}

try {
  pendingMeta = JSON.parse(String($('Готовим pending интеракцию').item.json.pendingOptionsJson || ''))
} catch {}

if (!pendingMeta || Object.keys(pendingMeta).length === 0) {
  try {
    pendingMeta = JSON.parse(String($('Выбираем активную задачу').item.json.task.pending_options_json || '{}'))
  } catch {
    pendingMeta = {}
  }
}

return {
  json: {
    deliveredPendingOptionsJson: JSON.stringify({
      ...pendingMeta,
      deliveredAt: new Date().toISOString(),
    }),
  },
}

const task = $('Выбираем активную задачу').item.json.task
let pendingMeta = {}

try {
  pendingMeta = JSON.parse(String(task.pending_options_json || '{}'))
} catch {
  pendingMeta = {}
}

const requestId = String(pendingMeta.requestId || '').trim()
const deliveredAt = String(pendingMeta.deliveredAt || '').trim()
const interactionType = Array.isArray(pendingMeta.questions) ? 'question' : String(pendingMeta.type || 'permission').trim()
const answers = Array.isArray(pendingMeta.answers) ? pendingMeta.answers : []
const rejectRequested = pendingMeta.rejectRequested === true
const permissionReply = String(pendingMeta.reply || '').trim()
const permissionMessage = String(pendingMeta.message || '').trim()
const hasAnswerPayload = interactionType === 'question'
  ? Boolean(requestId) && (rejectRequested || answers.length > 0)
  : Boolean(requestId) && Boolean(permissionReply)
const shouldSendQuestion = Boolean(requestId) && !hasAnswerPayload && !deliveredAt && String(task.pending_question || '').trim()
const deliveredPendingMeta = {
  ...pendingMeta,
  deliveredAt: new Date().toISOString(),
}

return {
  json: {
    interactionType,
    requestId,
    requestAction: rejectRequested ? 'reject' : 'reply',
    answers,
    permissionReply,
    permissionMessage,
    hasAnswerPayload,
    shouldSendQuestion,
    deliveredPendingOptionsJson: JSON.stringify(deliveredPendingMeta),
  },
}

const workerPackage = $('Готовим пакеты worker-ов').item.json
const activeTasks = Array.isArray(workerPackage.activeTasks) ? workerPackage.activeTasks : []
const selectedTask = activeTasks[0] || null

return {
  json: {
    task: selectedTask,
    taskStatus: String(selectedTask?.status || '').trim(),
    sessionId: String(selectedTask?.session_id || '').trim(),
    pendingQuestion: String(selectedTask?.pending_question || '').trim(),
    pendingOptionsJson: String(selectedTask?.pending_options_json || '[]'),
  },
}

const task = $('Выбираем активную задачу').item.json.task
const rawItems = $('Получаем pending вопросы OpenCode').all().map((item) => item.json)
const requests = rawItems
  .flatMap((item) => Array.isArray(item) ? item : [item])
  .filter((item) => item && !item.error)

const request = requests.find((item) => String(item.sessionID || '').trim() === String(task.session_id || '').trim())

if (!request) {
  return {
    json: {
      hasQuestion: false,
      pendingQuestionText: '',
      pendingOptionsJson: '[]',
    },
  }
}

const questions = Array.isArray(request.questions) ? request.questions : []
const blocks = questions.map((question, index) => {
  const lines = []
  const header = String(question.header || `Вопрос ${index + 1}`).trim()
  const body = String(question.question || '').trim()
  const options = Array.isArray(question.options) ? question.options : []

  lines.push(`${index + 1}. ${header}`)
  if (body) lines.push(body)

  if (options.length > 0) {
    lines.push('')
    options.forEach((option, optionIndex) => {
      const label = String(option.label || '').trim()
      const description = String(option.description || '').trim()
      lines.push(`${optionIndex + 1}. ${label}${description ? ` - ${description}` : ''}`)
    })
  }

  lines.push('')
  lines.push(question.multiple
    ? 'Можно выбрать несколько вариантов: перечислите номера или названия через запятую.'
    : 'Выберите один вариант: ответьте номером или точным названием.')

  if (question.custom !== false) {
    lines.push('Если подходящего варианта нет, можно ответить своим текстом.')
  }

  return lines.join('\n').trim()
})

const pendingQuestionText = [
  `OpenCode ждёт уточнение по задаче ${task.task_key}.`,
  questions.length > 1
    ? 'В одном запросе несколько вопросов. Ответьте несколькими непустыми строками в том же порядке, что и вопросы ниже.'
    : 'Ответьте номером варианта, точным названием или своим текстом, если это разрешено.',
  'Если одновременно ожидаются ответы по нескольким задачам, отвечайте в формате `task_key: ваш ответ`.',
  '',
  blocks.join('\n\n'),
  '',
  'Для отклонения вопроса отправьте `/reject` или `task_key: /reject`.',
].join('\n').trim()

const pendingMeta = {
  requestId: String(request.id || '').trim(),
  questions: questions.map((question) => ({
    question: String(question.question || '').trim(),
    header: String(question.header || '').trim(),
    multiple: Boolean(question.multiple),
    custom: question.custom !== false,
    options: (Array.isArray(question.options) ? question.options : []).map((option) => ({
      label: String(option.label || '').trim(),
      description: String(option.description || '').trim(),
    })),
  })),
  answers: null,
  rejectRequested: false,
}

return {
  json: {
    hasQuestion: true,
    pendingQuestionText,
    pendingOptionsJson: JSON.stringify(pendingMeta),
  },
}

let source = null

try {
  const permission = $('Ищем permission для сессии').item.json
  if (permission && permission.hasPermission) source = permission
} catch {}

if (!source) {
  try {
    const question = $('Ищем вопрос для сессии').item.json
    if (question && question.hasQuestion) source = question
  } catch {}
}

return {
  json: {
    pendingQuestionText: String(source?.pendingQuestionText || '').trim(),
    pendingOptionsJson: String(source?.pendingOptionsJson || '[]'),
  },
}

const task = $('Выбираем активную задачу').item.json.task
const statusMap = $('Получаем статусы сессий OpenCode').first().json || {}
const sessionStatus = statusMap[String(task.session_id || '').trim()] || {}
const statusType = String(sessionStatus.type || '').trim()

return {
  json: {
    statusType,
    isIdle: statusType === 'idle',
  },
}
